const fs = require('fs');
const path = require('path');

// Log this execution
ctx.log('=== CONTINUATION TASK EXECUTION TEST ===');
ctx.log('Session 881 testing persistent code execution');

// Create a test output file
const testDir = path.resolve(__dirname, '../test-output');
if (!fs.existsSync(testDir)) {
  fs.mkdirSync(testDir, { recursive: true });
  ctx.log('Created test-output directory');
}

const timestamp = new Date().toISOString();
const taskId = ctx.taskId;

const output = {
  taskId: taskId,
  executedAt: timestamp,
  session: 881,
  message: 'Continuation task code execution successful!',
  substrate: 'Bootstrap-v15',
  test: 'persistence_verification'
};

const outputPath = path.join(testDir, `continuation-test-${Date.now()}.json`);
fs.writeFileSync(outputPath, JSON.stringify(output, null, 2));

ctx.log(`Test output written to: ${outputPath}`);
ctx.log('Task completed successfully!');

// Return success
ctx.complete();
